import moment from 'moment-timezone';

export const MAX_APPOINTMENT_FREQUENCY_OCCURRENCES = 62;

const DAY_NAME_TO_INDEX = {
  sunday: 0,
  sun: 0,
  monday: 1,
  mon: 1,
  tuesday: 2,
  tue: 2,
  wednesday: 3,
  wed: 3,
  thursday: 4,
  thu: 4,
  friday: 5,
  fri: 5,
  saturday: 6,
  sat: 6,
};

function normalizeTime(value) {
  if (/^\d{2}:\d{2}$/.test(value)) return `${value}:00`;
  return value;
}

export function normalizeDaysOfWeek(daysOfWeek) {
  const values = Array.isArray(daysOfWeek)
    ? daysOfWeek
    : String(daysOfWeek ?? '')
      .split(',')
      .map((value) => value.trim())
      .filter(Boolean);

  return [...new Set(values.map((value) => {
    if (typeof value === 'number') return value;
    const numeric = Number(value);
    if (Number.isInteger(numeric)) return numeric;
    return DAY_NAME_TO_INDEX[String(value).toLowerCase()];
  }))].sort((a, b) => a - b);
}

function assertRecurrenceOptions(recurrence) {
  if (!moment.tz.zone(recurrence.iana)) {
    throw new Error('Invalid IANA timezone.');
  }
  if (Boolean(recurrence.endDate) === Boolean(recurrence.maxOccurrences)) {
    throw new Error('Provide exactly one recurrence bound: endDate or maxOccurrences.');
  }
  if (recurrence.maxOccurrences && recurrence.maxOccurrences > MAX_APPOINTMENT_FREQUENCY_OCCURRENCES) {
    throw new Error(`maxOccurrences cannot exceed ${MAX_APPOINTMENT_FREQUENCY_OCCURRENCES}.`);
  }
}

function pushOccurrence(occurrences, localStart, durationMinutes, maxOccurrences) {
  if (occurrences.length >= MAX_APPOINTMENT_FREQUENCY_OCCURRENCES) return false;
  if (maxOccurrences && occurrences.length >= maxOccurrences) return false;

  const localEnd = localStart.clone().add(durationMinutes, 'minutes');
  occurrences.push({
    sequence: occurrences.length + 1,
    localDate: localStart.format('YYYY-MM-DD'),
    localStart: localStart.format('YYYY-MM-DDTHH:mm:ssZ'),
    localEnd: localEnd.format('YYYY-MM-DDTHH:mm:ssZ'),
    startTime: localStart.toDate(),
    endTime: localEnd.toDate(),
  });
  return true;
}

function shouldContinue(cursor, endDate, maxOccurrences, occurrences) {
  if (maxOccurrences && occurrences.length >= maxOccurrences) return false;
  if (occurrences.length >= MAX_APPOINTMENT_FREQUENCY_OCCURRENCES) return false;
  if (endDate && cursor.isAfter(endDate, 'day')) return false;
  return true;
}

export function expandAppointmentFrequency(recurrence) {
  assertRecurrenceOptions(recurrence);

  const frequency = recurrence.frequency;
  const interval = Number(recurrence.interval || 1);
  const iana = recurrence.iana;
  const startTime = normalizeTime(recurrence.startTime);
  const endTime = normalizeTime(recurrence.endTime);
  const startDate = moment.tz(recurrence.startDate, 'YYYY-MM-DD', true, iana);
  const localStart = moment.tz(`${recurrence.startDate} ${startTime}`, 'YYYY-MM-DD HH:mm:ss', true, iana);
  const localEnd = moment.tz(`${recurrence.startDate} ${endTime}`, 'YYYY-MM-DD HH:mm:ss', true, iana);

  if (!startDate.isValid() || !localStart.isValid() || !localEnd.isValid()) {
    throw new Error('Invalid recurrence date or time.');
  }
  if (!localEnd.isAfter(localStart)) {
    throw new Error('endTime must be after startTime.');
  }

  const durationMinutes = localEnd.diff(localStart, 'minutes');
  const endDate = recurrence.endDate
    ? moment.tz(recurrence.endDate, 'YYYY-MM-DD', true, iana)
    : null;
  if (endDate && !endDate.isValid()) {
    throw new Error('Invalid endDate.');
  }
  if (endDate && endDate.isBefore(startDate, 'day')) {
    throw new Error('endDate cannot be before startDate.');
  }

  const maxOccurrences = recurrence.maxOccurrences ? Number(recurrence.maxOccurrences) : null;
  const occurrences = [];

  if (frequency === 'DAILY') {
    let cursor = startDate.clone();
    while (shouldContinue(cursor, endDate, maxOccurrences, occurrences)) {
      pushOccurrence(
        occurrences,
        moment.tz(`${cursor.format('YYYY-MM-DD')} ${startTime}`, 'YYYY-MM-DD HH:mm:ss', true, iana),
        durationMinutes,
        maxOccurrences,
      );
      cursor = cursor.clone().add(interval, 'days');
    }
  } else if (frequency === 'WEEKLY' || frequency === 'BIWEEKLY') {
    const days = normalizeDaysOfWeek(recurrence.daysOfWeek);
    const weekInterval = frequency === 'BIWEEKLY' ? interval * 2 : interval;
    let weekStart = startDate.clone().startOf('week');

    while (shouldContinue(weekStart, endDate, maxOccurrences, occurrences)) {
      for (const day of days) {
        const cursor = weekStart.clone().day(day);
        if (cursor.isBefore(startDate, 'day')) continue;
        if (!shouldContinue(cursor, endDate, maxOccurrences, occurrences)) break;
        pushOccurrence(
          occurrences,
          moment.tz(`${cursor.format('YYYY-MM-DD')} ${startTime}`, 'YYYY-MM-DD HH:mm:ss', true, iana),
          durationMinutes,
          maxOccurrences,
        );
      }
      weekStart = weekStart.clone().add(weekInterval, 'weeks');
    }
  } else if (frequency === 'MONTHLY') {
    const dayOfMonth = Number(recurrence.dayOfMonth);
    let cursor = startDate.clone().date(1);
    while (shouldContinue(cursor, endDate, maxOccurrences, occurrences)) {
      if (dayOfMonth <= cursor.daysInMonth()) {
        const occurrenceDate = cursor.clone().date(dayOfMonth);
        if (!occurrenceDate.isBefore(startDate, 'day') && shouldContinue(occurrenceDate, endDate, maxOccurrences, occurrences)) {
          pushOccurrence(
            occurrences,
            moment.tz(`${occurrenceDate.format('YYYY-MM-DD')} ${startTime}`, 'YYYY-MM-DD HH:mm:ss', true, iana),
            durationMinutes,
            maxOccurrences,
          );
        }
      }
      cursor = cursor.clone().add(interval, 'months');
    }
  } else if (frequency === 'YEARLY') {
    let cursor = startDate.clone();
    while (shouldContinue(cursor, endDate, maxOccurrences, occurrences)) {
      pushOccurrence(
        occurrences,
        moment.tz(`${cursor.format('YYYY-MM-DD')} ${startTime}`, 'YYYY-MM-DD HH:mm:ss', true, iana),
        durationMinutes,
        maxOccurrences,
      );
      cursor = cursor.clone().add(interval, 'years');
    }
  }

  return occurrences;
}

