import crypto from 'crypto';
import { Op, QueryTypes } from 'sequelize';
import { validateTimeSlotQuery } from '../../database/functions/validateTimeSlotAvailability.js';
import { REASON_TYPE, STATUS } from '../../enums/models.js';
import BadRequestError from '../../exceptions/badRequestError.js';
import ConflictError from '../../exceptions/conflictError.js';
import NotFoundError from '../../exceptions/notFoundError.js';
import AppointmentCalendarSync from '../../services/appointmentCalendarSync.js';
import AppointmentService from '../../services/appointmentService.js';
import { calculateRemindAt } from '../../utils/appointment/appointmentPayload.js';
import { parseAppointmentActionQueryFlags } from '../../utils/appointment/appointmentQueryFlags.js';
import { buildSlotValidationReplacements } from '../../utils/appointment/slotValidationReplacements.js';
import { attachDashboardRbac } from '../../utils/auth/dashboardRbac.js';
import DeleteAvailabilityCache from '../../utils/cache/redisDeleteByUuid.js';
import resetCustomer from '../../utils/customer/resetCustomer.js';
import {
  autoSendAllNotifications,
  notificationTypes,
} from '../../utils/notifications/sendNotification.js';
import { processWebhooks } from '../../utils/webhooks/dispatch.js';
import { expandAppointmentFrequency } from '../../utils/appointmentFrequency/recurrence.js';
import CrudController from '../crudController.js';
import * as appointmentDashboardRbac from '../appointment/appointmentDashboardRbac.js';
import { APPOINTMENT_FREQUENCY_STATUS } from '../../models/AppointmentFrequency.js';

class AppointmentFrequencyController extends CrudController {
  #associationService;
  #calendarSync;

  constructor(req, res, next) {
    super(req, res, next, 'AppointmentFrequency');
    this.#associationService = new AppointmentService(this.models);
    this.#calendarSync = new AppointmentCalendarSync(this.models);
  }

  async previewAppointmentFrequency() {
    const context = await this.#buildContext();
    return this.#preview(context);
  }

  async createAppointmentFrequency() {
    const idempotencyKey = this.#getIdempotencyKey();
    const context = await this.#buildContext();
    const idempotencyRequestHash = this.#buildIdempotencyRequestHash(context);
    const existingReplay = await this.#buildIdempotentReplay(
      idempotencyKey,
      idempotencyRequestHash,
    );
    if (existingReplay) return existingReplay;

    let created;
    try {
      created = await this.transaction(async (transaction) => {
        const preview = await this.#preview(context, transaction);
        const allOrNothing = this.body.allOrNothing !== false;

        if (allOrNothing && preview.conflicts.length > 0) {
          throw new BadRequestError('One or more occurrences are not available.', {
            errors: preview.conflicts,
            conflicts: preview.conflicts,
            occurrences: preview.occurrences,
          });
        }
        const {
          Customer,
          CustomFields,
          skip_notifications = false,
          recurrence,
          allOrNothing: _allOrNothing,
          ...createParams
        } = this.body;
        const customer = await this.#findOrCreateCustomer(Customer, context.LocationId, transaction);

        const series = await this.models.AppointmentFrequency.create(
          {
            CompanyId: this.company.id,
            LocationId: context.LocationId,
            ServiceId: context.ServiceId,
            CustomerId: customer.id,
            ResourceIds: context.ResourceIds,
            frequency: recurrence.frequency,
            interval: recurrence.interval || 1,
            daysOfWeek: Array.isArray(recurrence.daysOfWeek)
              ? recurrence.daysOfWeek.join(',')
              : recurrence.daysOfWeek ?? null,
            dayOfMonth: recurrence.dayOfMonth ?? null,
            startDate: recurrence.startDate,
            endDate: recurrence.endDate ?? null,
            maxOccurrences: recurrence.maxOccurrences ?? null,
            startTime: recurrence.startTime,
            endTime: recurrence.endTime,
            iana: recurrence.iana,
            status: APPOINTMENT_FREQUENCY_STATUS.ACTIVE,
            idempotencyKey,
            idempotencyRequestHash,
            bookedBy: createParams.bookedBy ?? null,
            notes: createParams.notes ?? null,
            location: createParams.location ?? null,
            ipAddress: createParams.ipAddress ?? null,
            CustomFields: CustomFields || {},
          },
          { transaction },
        );

        const appointments = [];
        const availableOccurrences = preview.occurrences.filter((occurrence) => occurrence.available);
        for (const occurrence of availableOccurrences) {
          const appointment = await this.#createOccurrenceAppointment({
            series,
            occurrence,
            customer,
            context,
            createParams,
            customFields: CustomFields || {},
            transaction,
          });
          appointments.push(appointment);
        }

        await this.#clearAvailabilityCache(context.ServiceId, ...context.ResourceIds);

        return {
          series,
          appointments,
          flags: context.flags,
          skipNotifications: skip_notifications,
        };
      });
    } catch (error) {
      if (this.#isIdempotencyUniqueError(error)) {
        const replay = await this.#buildIdempotentReplay(
          idempotencyKey,
          idempotencyRequestHash,
        );
        if (replay) return replay;
      }
      throw error;
    }

    if (!created.skipNotifications) {
      await this.#dispatchCreatedAppointmentSideEffects(
        created.appointments,
        created.flags,
      );
    }

    const reloadedSeries = await this.#findSeries(created.series.id);
    return {
      body: {
        ...reloadedSeries.toJSON(),
        appointmentsCreated: created.appointments.length,
        idempotentReplay: false,
      },
      statusCode: 201,
    };
  }

  async getAppointmentFrequency() {
    const series = await this.#findSeries(this.id);
    await appointmentDashboardRbac.assertAppointmentReadRbac(
      this,
      series.LocationId,
      series.ServiceId,
    );
    return series;
  }

  async cancelFutureAppointmentFrequency() {
    const series = await this.#findSeries(this.id);
    await appointmentDashboardRbac.assertAppointmentWriteRbac(
      this,
      series.LocationId,
      series.ServiceId,
    );
    appointmentDashboardRbac.assertAppointmentResourceIdsRbac(this, series.ResourceIds || []);

    const canceled = await this.transaction(async (transaction) => {
      const appointments = await this.models.Appointment.findAll({
        where: {
          AppointmentFrequencyId: series.id,
          status: { [Op.in]: [STATUS.BK, STATUS.IN, STATUS.RS] },
          frequencyOccurrenceStart: { [Op.gte]: new Date() },
        },
        include: this.#associationService.getCancelAppointmentIncludes(),
        order: [['frequencySequence', 'ASC']],
        transaction,
      });

      for (const appointment of appointments) {
        await appointment.update({ status: STATUS.CN }, { transaction });
        await appointment.Unavailability?.destroy({ transaction });
        await appointment.PadUnavailability?.destroy({ transaction });
      }

      await series.update(
        { status: APPOINTMENT_FREQUENCY_STATUS.CANCELED },
        { transaction },
      );
      await this.#clearAvailabilityCache(series.ServiceId, ...(series.ResourceIds || []));

      const reloadedSeries = await this.#findSeries(series.id, transaction);
      return {
        series: reloadedSeries,
        appointments,
        appointmentsCanceled: appointments.length,
      };
    });

    await this.#dispatchCancelledAppointmentSideEffects(canceled.appointments);

    return {
      ...canceled.series.toJSON(),
      appointmentsCanceled: canceled.appointmentsCanceled,
    };
  }

  async #buildContext() {
    const { LocationId, ServiceId } = this.query;
    const ResourceIds = this.#normalizeResourceIds(this.query.ResourceIds);
    if (ResourceIds.length === 0) {
      throw new BadRequestError('ResourceIds are required for appointment frequency.');
    }

    await appointmentDashboardRbac.assertAppointmentWriteRbac(this, LocationId, ServiceId);
    const policy = attachDashboardRbac(this.req);
    const resourceCheckIds =
      ResourceIds.length > 0
        ? ResourceIds
        : policy.linkedResourceId
          ? [policy.linkedResourceId]
          : [];
    appointmentDashboardRbac.assertAppointmentResourceIdsRbac(this, resourceCheckIds);

    const [location, service, resources] = await Promise.all([
      this.models.Location.findOne({
        where: { id: LocationId, CompanyId: this.company.id },
      }),
      this.models.Service.findOne({
        where: { id: ServiceId, CompanyId: this.company.id },
      }),
      this.models.Resource.findAll({
        where: { id: ResourceIds, CompanyId: this.company.id },
      }),
    ]);

    if (!location) throw new NotFoundError('Location not found');
    if (!service) throw new NotFoundError('Service not found');
    if (resources.length !== ResourceIds.length) {
      throw new BadRequestError('One or more resources not found or do not belong to this company.');
    }

