import { expect } from 'chai';
import { expandAppointmentFrequency } from '../../../utils/appointmentFrequency/recurrence.js';

describe('appointment frequency recurrence expansion', () => {
  it('expands weekly wall-clock occurrences across DST', () => {
    const occurrences = expandAppointmentFrequency({
      frequency: 'WEEKLY',
      interval: 1,
      daysOfWeek: [0],
      startDate: '2030-03-03',
      startTime: '09:00:00',
      endTime: '09:30:00',
      iana: 'America/New_York',
      maxOccurrences: 3,
    });

    expect(occurrences).to.have.length(3);
    expect(occurrences.map((occurrence) => occurrence.localStart)).to.deep.equal([
      '2030-03-03T09:00:00-05:00',
      '2030-03-10T09:00:00-04:00',
      '2030-03-17T09:00:00-04:00',
    ]);
  });

  it('caps expanded occurrences at 62', () => {
    expect(() => expandAppointmentFrequency({
      frequency: 'DAILY',
      interval: 1,
      startDate: '2030-01-01',
      startTime: '09:00:00',
      endTime: '09:30:00',
      iana: 'UTC',
      maxOccurrences: 63,
    })).to.throw('maxOccurrences cannot exceed 62');
  });

  it('requires exactly one recurrence bound', () => {
    expect(() => expandAppointmentFrequency({
      frequency: 'DAILY',
      interval: 1,
      startDate: '2030-01-01',
      startTime: '09:00:00',
      endTime: '09:30:00',
      iana: 'UTC',
    })).to.throw('Provide exactly one recurrence bound');
  });

  it('expands monthly occurrences on valid matching days only', () => {
    const occurrences = expandAppointmentFrequency({
      frequency: 'MONTHLY',
      interval: 1,
      dayOfMonth: 31,
      startDate: '2030-01-30',
      startTime: '09:00:00',
      endTime: '09:30:00',
      iana: 'UTC',
      maxOccurrences: 3,
    });

    expect(occurrences.map((occurrence) => occurrence.localDate)).to.deep.equal([
      '2030-01-31',
      '2030-03-31',
      '2030-05-31',
    ]);
  });
});

